module top_module(s,r,clk,rst,obf_q,qb);input s,r,clk,rst;
	output obf_q,qb;
	wire s,r,clk,rst,qb;
	reg obf_q;
always @ (posedge clk)
	begin
	if(rst)
	obf_q<=1'b0;
		else if (s==1'b0 && r==1'b0)
				obf_q<=obf_q;
		else if (s==1'b0&& r==1'b1)
				obf_q<=1'b0;
		else if (s==1'b1 && r==1'b0)
				obf_q<=1'b1;
		else if (s==1'b1 && r==1'b1)
		obf_q<=1'bx;
		end
		assign qb=~obf_q;endmodule
